(function(s){"use strict";const a={modelCache:null,apiUrl:null,init:function(n){this.apiUrl=n},loadAllModels:async function(){if(this.modelCache)return this.modelCache;try{const o=await new ElanRegistryAPI().post(this.apiUrl,{action:"getAllYearModels"});return o.success&&o.yearModels?(this.modelCache=o.yearModels,this.modelCache):(console.error("Failed to load models:",o.message),{})}catch(n){return console.error("Error loading models:",n),{}}},populateModelDropdown:async function(n,o){if(!n||!o||o.length===0)return;const r=await this.loadAllModels();o.find("option:not(:first)").remove();const e=r[n]||[];e.forEach(function(t){o.append(new Option(t.text,t.value))}),o.prop("disabled",e.length===0),o.trigger("change")},getModelByValue:async function(n){const o=await this.loadAllModels();for(const r in o){const e=o[r].find(t=>t.value===n);if(e)return e}return null}};s.ModelLoader=a})(window);
